import React, { useState, useEffect } from "react";
import axios from "axios";

function App() {
  const [files, setFiles] = useState([]);

  useEffect(() => {
    axios.get("http://localhost:5000/files").then(res => setFiles(res.data));
  }, []);

  const handleUpload = async (e) => {
    const formData = new FormData();
    formData.append("file", e.target.files[0]);
    await axios.post("http://localhost:5000/upload", formData);
    const res = await axios.get("http://localhost:5000/files");
    setFiles(res.data);
  };

  const handleOpen = async (filename) => {
    await axios.get(`http://localhost:5000/open/${filename}`);
  };

  return (
    <div>
      <h1>İSG Panel Dosya Yükleme</h1>
      <input type="file" onChange={handleUpload} />
      <ul>
        {files.map(f => (
          <li key={f}>
            {f} <button onClick={() => handleOpen(f)}>Aç</button>
          </li>
        ))}
      </ul>
    </div>
  );
}

export default App;
